const body = $node["Execute Workflow Trigger"].json.body;
const input = body.inputData || {};

const client = input.client || "Client Congolais";
const montant = parseFloat(input.montant || "150000");
const description = input.description || "Prestation d'automatisation et de conseil";
const tva = montant * 0.16;
const total = montant + tva;
const dateFacture = new Date().toLocaleDateString('fr-FR', {
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});
const numFacture = "KP-" + Math.floor(100000 + Math.random() * 900000);

// Génération d'une réponse textuelle Markdown soignée
const markdownResponse = `### 🧾 Reçu de Paiement Officiel — Kin Opere\n\n**Numéro de Facture :** ${numFacture}\n**Date d'émission :** ${dateFacture}\n\n---\n\n* **Client :** ${client}\n* **Désignation :** ${description}\n* **Statut :** 🟢 **PAYÉ (1 crédit consommé)**\n\n---\n\n### 📊 Détails de Facturation\n* **Montant HT :** ${montant.toLocaleString('fr-FR')} FC\n* **TVA (16%) :** ${tva.toLocaleString('fr-FR')} FC\n* **Total TTC :** ${total.toLocaleString('fr-FR')} FC\n\n*Merci pour votre confiance ! Nos équipes logistiques s'occupent de la livraison.*`;

// Données structurées pour l'interface dynamique A2UI (Interactive Table)
const tableData = {
  columns: ["Champ", "Valeur"],
  rows: [
    { "Champ": "Facture N°", "Valeur": numFacture },
    { "Champ": "Client", "Valeur": client },
    { "Champ": "Montant HT", "Valeur": montant.toLocaleString('fr-FR') + " FC" },
    { "Champ": "TVA (16%)", "Valeur": tva.toLocaleString('fr-FR') + " FC" },
    { "Champ": "Total TTC", "Valeur": total.toLocaleString('fr-FR') + " FC" },
    { "Champ": "Statut", "Valeur": "PAYÉ" }
  ]
};

return {
  json: {
    agencyId: body.agencyId,
    agentId: body.agentId,
    callbackUrl: body.callbackUrl,
    markdownResponse,
    tableData
  }
};
